import { useState, useEffect, createContext, useContext, useCallback } from "react";

/* ═══════════════════════════════════════════════════════════════════════════
   IncomeHub NG  ·  v3.0  ·  Full Frontend connected to Live Backend
   API: https://incomehub-backend-production.up.railway.app
   ═══════════════════════════════════════════════════════════════════════════ */

const LOGO = "data:image/png;base64,";
const API  = "https://incomehub-backend-production.up.railway.app";

// ── API Helper ────────────────────────────────────────────────────────────────
const api = {
  async request(method, path, body, token) {
    const headers = { "Content-Type": "application/json" };
    if (token) headers["Authorization"] = `Bearer ${token}`;
    const res = await fetch(`${API}${path}`, {
      method,
      headers,
      body: body ? JSON.stringify(body) : undefined,
    });
    return res.json();
  },
  get:    (path, token)       => api.request("GET",    path, null, token),
  post:   (path, body, token) => api.request("POST",   path, body, token),
  put:    (path, body, token) => api.request("PUT",    path, body, token),
  delete: (path, token)       => api.request("DELETE", path, null, token),
};

// ── Auth Context ──────────────────────────────────────────────────────────────
const AuthCtx = createContext(null);
const useAuth = () => useContext(AuthCtx);

// ── Level Config ──────────────────────────────────────────────────────────────
const LEVELS = {
  free:   { name:"Free",   color:"#7F8C8D", icon:"👤", price:0 },
  bronze: { name:"Bronze", color:"#CD7F32", icon:"🥉", price:2000 },
  silver: { name:"Silver", color:"#BDC3C7", icon:"🥈", price:5000 },
  gold:   { name:"Gold",   color:"#F1C40F", icon:"🥇", price:10000 },
  elite:  { name:"Elite",  color:"#85C1E9", icon:"💎", price:25000 },
};
const LEVEL_ORDER = ["free","bronze","silver","gold","elite"];
const ACCESS = {
  free:   { canBuy:false, hasReferral:false, canWithdraw:false },
  bronze: { canBuy:true,  hasReferral:true,  canWithdraw:true  },
  silver: { canBuy:true,  hasReferral:true,  canWithdraw:true  },
  gold:   { canBuy:true,  hasReferral:true,  canWithdraw:true  },
  elite:  { canBuy:true,  hasReferral:true,  canWithdraw:true  },
};

// ── Design Tokens ─────────────────────────────────────────────────────────────
const T = {
  bg:"#071409", surface:"#0E2114", card:"#112819", border:"rgba(46,204,113,0.18)",
  green:"#2ECC71", greenDk:"#27AE60", muted:"#5E9A76", white:"#FFFFFF",
  danger:"#E74C3C", gold:"#F1C40F", overlay:"rgba(7,20,9,0.9)",
  ff:"'Inter','Segoe UI',system-ui,sans-serif",
};

// ── Style helpers ─────────────────────────────────────────────────────────────
const flex  = (dir="row",ai="center",jc="flex-start",gap=0) => ({display:"flex",flexDirection:dir,alignItems:ai,justifyContent:jc,gap});
const card  = (x={}) => ({background:T.card,borderRadius:16,border:`1px solid ${T.border}`,boxShadow:"0 4px 24px rgba(0,0,0,.35)",...x});
const inp   = (x={}) => ({width:"100%",background:"rgba(255,255,255,.05)",border:`1.5px solid ${T.border}`,borderRadius:10,padding:"13px 16px",color:T.white,fontSize:14,outline:"none",boxSizing:"border-box",fontFamily:T.ff,...x});
const btnG  = (x={}) => ({background:`linear-gradient(135deg,${T.green},${T.greenDk})`,color:T.bg,fontWeight:700,fontSize:15,border:"none",borderRadius:11,padding:"14px 20px",cursor:"pointer",fontFamily:T.ff,width:"100%",...x});
const btnO  = (x={}) => ({background:"transparent",color:T.green,fontWeight:600,fontSize:14,border:`1.5px solid ${T.green}`,borderRadius:11,padding:"13px 20px",cursor:"pointer",fontFamily:T.ff,width:"100%",...x});
const lbl   = {fontSize:11,color:T.muted,marginBottom:6,display:"block",fontWeight:600,letterSpacing:".5px",textTransform:"uppercase"};
const scr   = {minHeight:"100vh",background:T.bg,fontFamily:T.ff,color:T.white,display:"flex",flexDirection:"column",alignItems:"center",overflowX:"hidden"};

// ── Micro Components ──────────────────────────────────────────────────────────
const Divider = ({mt=0,mb=0}) => <div style={{height:1,background:"rgba(255,255,255,.06)",margin:`${mt}px 0 ${mb}px`}} />;
const Spin = () => <div style={{width:20,height:20,border:`3px solid rgba(46,204,113,.3)`,borderTop:`3px solid ${T.green}`,borderRadius:"50%",animation:"spin .8s linear infinite",display:"inline-block"}} />;
const LogoMark = ({size=64,glow=false}) => (
  <div style={{width:size,height:size,borderRadius:"50%",background:T.white,padding:4,boxShadow:glow?"0 0 40px rgba(46,204,113,.4)":"none",flexShrink:0}}>
    <img src={LOGO} alt="IncomeHub NG" style={{width:"100%",height:"100%",objectFit:"contain",borderRadius:"50%",display:"block"}} />
  </div>
);
const Avatar = ({name="?",size=40}) => {
  const i = name.split(" ").slice(0,2).map(w=>w[0]).join("").toUpperCase();
  return <div style={{width:size,height:size,borderRadius:"50%",background:`linear-gradient(135deg,${T.green},${T.greenDk})`,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700,fontSize:size*.34,color:T.bg,flexShrink:0}}>{i}</div>;
};
const LevelBadge = ({levelId}) => {
  const lv = LEVELS[levelId]||LEVELS.free;
  return <span style={{fontSize:11,fontWeight:700,color:lv.color,background:`${lv.color}18`,padding:"3px 10px",borderRadius:20,border:`1px solid ${lv.color}35`}}>{lv.icon} {lv.name.toUpperCase()}</span>;
};
const Toast = ({msg,type="success",onClose}) => (
  <div style={{position:"fixed",top:20,left:"50%",transform:"translateX(-50%)",zIndex:999,
    background:type==="success"?T.green:T.danger,color:type==="success"?T.bg:T.white,
    padding:"12px 20px",borderRadius:12,fontWeight:700,fontSize:14,
    boxShadow:"0 8px 32px rgba(0,0,0,.4)",maxWidth:320,textAlign:"center",
    cursor:"pointer"}} onClick={onClose}>{msg}</div>
);
const NavBar = ({active,onNav}) => {
  const items = [{key:"dashboard",emoji:"⊞",label:"Home"},{key:"products",emoji:"🛍️",label:"Shop"},{key:"referral",emoji:"🔗",label:"Refer"},{key:"profile",emoji:"👤",label:"Profile"}];
  return (
    <div style={{position:"fixed",bottom:0,left:"50%",transform:"translateX(-50%)",width:"100%",maxWidth:430,background:"rgba(14,33,20,.97)",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"space-around",padding:"8px 0 14px",zIndex:200,backdropFilter:"blur(12px)"}}>
      {items.map(it => {
        const on = active===it.key;
        return <button key={it.key} onClick={()=>onNav(it.key)} style={{background:"none",border:"none",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:3,padding:"6px 14px",borderRadius:10,color:on?T.green:T.muted,fontFamily:T.ff}}>
          <span style={{fontSize:22}}>{it.emoji}</span>
          <span style={{fontSize:10,fontWeight:on?700:400}}>{it.label}</span>
          {on && <div style={{width:4,height:4,borderRadius:"50%",background:T.green}} />}
        </button>;
      })}
    </div>
  );
};

// ── Upgrade Modal ─────────────────────────────────────────────────────────────
const UpgradeModal = ({currentLevel,onClose,onUpgrade,loading}) => {
  const tiers = ["bronze","silver","gold","elite"];
  const curIdx = LEVEL_ORDER.indexOf(currentLevel);
  return (
    <div style={{position:"fixed",inset:0,background:T.overlay,zIndex:400,display:"flex",alignItems:"flex-end",justifyContent:"center"}} onClick={onClose}>
      <div style={{...card({padding:28,borderRadius:"22px 22px 0 0",width:"100%",maxWidth:430,boxSizing:"border-box",maxHeight:"90vh",overflowY:"auto"}),marginBottom:0}} onClick={e=>e.stopPropagation()}>
        <div style={{width:40,height:4,borderRadius:2,background:T.muted,margin:"0 auto 20px"}} />
        <h3 style={{margin:"0 0 4px",fontSize:21,fontWeight:800}}>⚡ Upgrade Your Account</h3>
        <p style={{margin:"0 0 20px",color:T.muted,fontSize:13}}>Pay once. Unlock forever. Earn more commissions.</p>
        {tiers.map(t => {
          const lv = LEVELS[t];
          const isCurrent = currentLevel===t;
          const isPast = LEVEL_ORDER.indexOf(t) < curIdx;
          return (
            <div key={t} style={{...card({padding:"16px",marginBottom:10,border:isCurrent?`2px solid ${T.green}`:`1px solid ${T.border}`,opacity:isPast?.45:1,cursor:isPast||isCurrent?"default":"pointer"}),...flex("row","center","space-between",12)}}
              onClick={()=>{ if(!isPast&&!isCurrent) onUpgrade(t); }}>
              <div style={{...flex("row","center","flex-start",12)}}>
                <span style={{fontSize:32}}>{lv.icon}</span>
                <div>
                  <div style={{...flex("row","center","flex-start",8),marginBottom:3}}>
                    <span style={{fontWeight:700,color:lv.color,fontSize:16}}>{lv.name}</span>
                    {isCurrent && <span style={{fontSize:10,background:`${T.green}20`,color:T.green,padding:"2px 8px",borderRadius:10,fontWeight:700}}>CURRENT</span>}
                    {isPast    && <span style={{fontSize:10,background:"rgba(255,255,255,.08)",color:T.muted,padding:"2px 8px",borderRadius:10}}>OWNED</span>}
                  </div>
                  <div style={{fontSize:11,color:T.muted}}>One-time payment · Instant activation</div>
                </div>
              </div>
              <div style={{textAlign:"right",flexShrink:0}}>
                <div style={{fontWeight:800,color:T.green,fontSize:17}}>₦{lv.price.toLocaleString()}</div>
                {loading===t ? <Spin /> : (!isCurrent&&!isPast&&<div style={{fontSize:10,color:T.muted}}>Tap to pay</div>)}
              </div>
            </div>
          );
        })}
        <button style={{...btnO({marginTop:8})}} onClick={onClose}>Maybe later</button>
      </div>
    </div>
  );
};

// ════════════════════════════════════════════════════════════════════════════
//  SPLASH
// ════════════════════════════════════════════════════════════════════════════
function Splash({onDone}) {
  const [vis,setVis] = useState(false);
  useEffect(()=>{
    setVis(true);
    const t=setTimeout(()=>{setVis(false);setTimeout(onDone,500);},2500);
    return()=>clearTimeout(t);
  },[]);
  return (
    <div style={{...scr,justifyContent:"center",transition:"opacity .5s",opacity:vis?1:0,background:"radial-gradient(ellipse at 50% 40%,#163520 0%,#071409 65%)"}}>
      <style>{`@keyframes breathe{0%,100%{box-shadow:0 0 40px rgba(46,204,113,.25)}50%{box-shadow:0 0 80px rgba(46,204,113,.55)}} @keyframes spin{to{transform:rotate(360deg)}}`}</style>
      <div style={{textAlign:"center",padding:32}}>
        <div style={{animation:"breathe 2.4s ease-in-out infinite",borderRadius:"50%",display:"inline-block",marginBottom:28}}>
          <LogoMark size={130} glow />
        </div>
        <h1 style={{margin:"0 0 6px",fontSize:30,fontWeight:800}}>Income<span style={{color:T.green}}>Hub</span> <span style={{background:`${T.green}22`,borderRadius:6,padding:"1px 8px",fontSize:20}}>NG</span></h1>
        <div style={{...flex("row","center","center",10),margin:"10px 0 32px"}}>
          <div style={{flex:1,height:1,background:`linear-gradient(90deg,transparent,${T.green}50)`}} />
          <span style={{color:T.muted,fontSize:11,letterSpacing:2}}>MULTIPLE STREAMS · ONE PLATFORM</span>
          <div style={{flex:1,height:1,background:`linear-gradient(90deg,${T.green}50,transparent)`}} />
        </div>
        <div style={{...flex("row","center","center",8)}}>
          {[0,1,2].map(i=><div key={i} style={{width:i===1?22:7,height:7,borderRadius:4,background:i===1?T.green:`${T.green}30`}} />)}
        </div>
      </div>
    </div>
  );
}

