//  PROFILE
// ════════════════════════════════════════════════════════════════════════════
function Profile({onNav,onUpgradeOpen,onLogout}) {
  const {user,token} = useAuth();
  const lv  = LEVELS[user.level]||LEVELS.free;
  const acc = ACCESS[user.level]||ACCESS.free;
  const fmt = n => `₦${(n||0).toLocaleString()}`;

  const sections = [
    {title:"Account",items:[
      {icon:"👤",label:"Edit Profile",sub:"Name, photo, bio"},
      {icon:"🏦",label:"Bank Accounts",sub:acc.canWithdraw?"Add or manage payout banks":"Upgrade to add bank account",locked:!acc.canWithdraw},
      {icon:"🔐",label:"Security",sub:"Password · 2FA · PIN"},
    ]},
    {title:"Earnings",items:[
      {icon:"📊",label:"Transaction History",sub:acc.canWithdraw?"Full earnings record":"Upgrade to view transactions",locked:!acc.canWithdraw},
      {icon:"🎁",label:"Reward Points",sub:"Tap to redeem",locked:user.level==="free"},
      {icon:"⭐",label:"Level Benefits",sub:`Your ${lv.name} perks`},
    ]},
    {title:"App",items:[
      {icon:"🔔",label:"Notifications",sub:"Control your alerts"},
      {icon:"🌐",label:"Language & Region",sub:"English · Nigeria"},
      {icon:"📞",label:"Help & Support",sub:"Chat, FAQ, contact us"},
      {icon:"ℹ️", label:"About IncomeHub NG",sub:"Version 3.0 · Terms · Privacy"},
    ]},
  ];

  return (
    <div style={{...scr,justifyContent:"flex-start",overflowY:"auto"}}>
      <div style={{width:"100%",maxWidth:430}}>
        {/* Hero */}
        <div style={{padding:"36px 20px 24px",background:`linear-gradient(160deg,#163520,${T.surface})`,borderBottom:`1px solid ${T.border}`,textAlign:"center"}}>
          <div style={{position:"relative",display:"inline-block",marginBottom:14}}>
            <Avatar name={user.fullName||"User"} size={86} />
            <div style={{position:"absolute",bottom:2,right:2,width:24,height:24,borderRadius:"50%",background:T.green,border:`2px solid ${T.bg}`,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:12}}>✏️</div>
          </div>
          <h2 style={{margin:"0 0 3px",fontSize:20,fontWeight:800}}>{user.fullName}</h2>
          <p style={{margin:"0 0 12px",color:T.muted,fontSize:13}}>{user.email}</p>
          <div style={{...flex("row","center","center",8)}}>
            <LevelBadge levelId={user.level} />
            {user.level==="free" && <button style={{...btnG({width:"auto",padding:"6px 14px",fontSize:12})}} onClick={onUpgradeOpen}>⚡ Upgrade</button>}
          </div>
        </div>

        {/* Stats */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)"}}>
          {[
            {v:acc.canWithdraw?fmt(user.totalEarned||0):"—",l:"Total Earned"},
            {v:acc.hasReferral?(user.referralCount||0).toString():"—",l:"Referrals"},
            {v:lv.name,l:"Current Level"},
          ].map((s,i)=>(
            <div key={i} style={{padding:"14px 8px",textAlign:"center",borderRight:i<2?`1px solid ${T.border}`:"none",borderBottom:`1px solid ${T.border}`}}>
              <div style={{fontSize:16,fontWeight:800,color:T.green}}>{s.v}</div>
              <div style={{fontSize:10,color:T.muted,marginTop:2}}>{s.l}</div>
            </div>
          ))}
        </div>

        {user.level==="free" && (
          <div style={{padding:"16px 16px 0"}}>
            <div style={{...card({padding:"14px 16px",background:"rgba(241,196,15,.07)",border:"1px solid rgba(241,196,15,.25)"}),...flex("row","center","space-between",12)}}>
              <span style={{fontSize:13,color:"#F5D87A"}}>🔒 Upgrade to unlock full profile features</span>
              <button onClick={onUpgradeOpen} style={{...btnG({width:"auto",padding:"8px 16px",fontSize:12})}}>Upgrade</button>
            </div>
          </div>
        )}

        {/* Menu */}
        <div style={{padding:"16px 16px 0"}}>
          {sections.map(sec=>(
            <div key={sec.title} style={{marginBottom:16}}>
              <p style={{margin:"0 0 8px 4px",fontSize:11,color:T.muted,textTransform:"uppercase",letterSpacing:1,fontWeight:600}}>{sec.title}</p>
              <div style={card({padding:4})}>
                {sec.items.map((item,i)=>(
                  <div key={i}>
                    <div style={{...flex("row","center","space-between",14),padding:"14px 12px",cursor:"pointer",opacity:item.locked?.6:1}} onClick={item.locked?onUpgradeOpen:undefined}>
                      <div style={{width:42,height:42,borderRadius:12,background:`${T.green}0D`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>{item.icon}</div>
                      <div style={{flex:1}}>
                        <div style={{fontSize:14,fontWeight:600,...flex("row","center","flex-start",6)}}>{item.label}{item.locked&&<span style={{fontSize:11}}>🔒</span>}</div>
                        <div style={{fontSize:11,color:T.muted,marginTop:1}}>{item.sub}</div>
                      </div>
                      <span style={{color:T.muted,fontSize:18,lineHeight:1}}>›</span>
                    </div>
                    {i<sec.items.length-1&&<Divider />}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        {/* Signout */}
        <div style={{padding:"0 16px 110px"}}>
          <button onClick={onLogout} style={{...btnO({color:T.danger,borderColor:T.danger}),display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
            <span>🚪</span> Sign Out
          </button>
          <p style={{textAlign:"center",margin:"16px 0 0",color:T.muted,fontSize:11}}>IncomeHub NG · v3.0 · Made in Nigeria 🇳🇬</p>
        </div>
      </div>
      <NavBar active="profile" onNav={onNav} />
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
//  ROOT APP
// ════════════════════════════════════════════════════════════════════════════
export default function App() {
  const [page,setPage]   = useState("splash");
  const [tab,setTab]     = useState("dashboard");
  const [user,setUser]   = useState(null);
  const [token,setToken] = useState(null);
  const [showUpgrade,setShowUpgrade] = useState(false);
  const [upgradeLoading,setUpgradeLoading] = useState(null);
  const [toast,setToast] = useState(null);

  const showToast = (msg,type="success") => {
    setToast({msg,type});
    setTimeout(()=>setToast(null),3000);
  };

  // Check for saved session on load
  useEffect(()=>{
    if(page==="splash") return;
    const savedToken = localStorage.getItem("ihng_token");
    const savedUser  = localStorage.getItem("ihng_user");
    if(savedToken && savedUser){
      setToken(savedToken);
      setUser(JSON.parse(savedUser));
      setPage("app");
    }
  },[page]);

  const handleLogin = (u,t) => { setUser(u); setToken(t); setPage("app"); showToast(`Welcome back, ${u.fullName?.split(" ")[0]}! 👋`); };
  const handleRegister = (u,t) => { setUser(u); setToken(t); setPage("app"); showToast("Account created! Welcome to IncomeHub NG 🎉"); };
  const handleLogout = () => { localStorage.removeItem("ihng_token"); localStorage.removeItem("ihng_user"); setUser(null); setToken(null); setPage("login"); };

  const refreshUser = useCallback(async () => {
    if(!token) return;
    const data = await api.get("/api/auth/me",token);
    if(data.success){ setUser(data.user); localStorage.setItem("ihng_user",JSON.stringify(data.user)); }
  },[token]);

  const handleUpgrade = async (targetLevel) => {
    setUpgradeLoading(targetLevel);
    try {
      const data = await api.post("/api/upgrade/initiate",{targetLevel},token);
      if(data.success && data.paymentUrl){
        window.open(data.paymentUrl,"_blank");
        showToast("Redirecting to payment... Complete it to activate your level! 💳");
        setShowUpgrade(false);
        // Poll for upgrade completion
        let attempts = 0;
        const poll = setInterval(async()=>{
          attempts++;
          await refreshUser();
          const updated = JSON.parse(localStorage.getItem("ihng_user")||"{}");
          if(updated.level===targetLevel || attempts>20){
            clearInterval(poll);
            if(updated.level===targetLevel) showToast(`🎉 You are now ${LEVELS[targetLevel].name}!`);
          }
        },5000);
      } else {
        showToast(data.message||"Could not initiate payment.","error");
      }
    } catch(e){ showToast("Network error. Please try again.","error"); }
    setUpgradeLoading(null);
  };

  const auth = { user, token, setUser, refreshUser };

  if(page==="splash")     return <Splash onDone={()=>setPage("onboarding")} />;
  if(page==="onboarding") return <Onboarding onDone={()=>setPage("login")} />;
  if(page==="login")      return <Login onLogin={handleLogin} onRegister={()=>setPage("register")} />;
  if(page==="register")   return <Register onRegister={handleRegister} onLogin={()=>setPage("login")} />;

  if(!user) return <Login onLogin={handleLogin} onRegister={()=>setPage("register")} />;

  const tabs = {
    dashboard: <Dashboard onNav={setTab} onUpgradeOpen={()=>setShowUpgrade(true)} />,
    products:  <Products  onNav={setTab} onUpgradeOpen={()=>setShowUpgrade(true)} />,
    referral:  <Referral  onNav={setTab} onUpgradeOpen={()=>setShowUpgrade(true)} />,
    profile:   <Profile   onNav={setTab} onUpgradeOpen={()=>setShowUpgrade(true)} onLogout={handleLogout} />,
  };

  return (
    <AuthCtx.Provider value={auth}>
      {toast && <Toast msg={toast.msg} type={toast.type} onClose={()=>setToast(null)} />}
      {tabs[tab]??tabs.dashboard}
      {showUpgrade && (
        <UpgradeModal
          currentLevel={user.level}
          onClose={()=>setShowUpgrade(false)}
          onUpgrade={handleUpgrade}
          loading={upgradeLoading}
        />
      )}
    </AuthCtx.Provider>
  );
}
